def max_vowels(s, k):
    vowels = set('aeiou')
    c = 0
    for i in range(k):
        if s[i] in vowels:
            c += 1
    best = c
    for i in range(k, len(s)):
        if s[i] in vowels:
            c += 1
        if s[i - k] in vowels:
            c -= 1
        if c > best:
            best = c
    return best

