def character_replacement(s, k):
    count = {}
    left = 0
    max_freq = 0
    best = 0
    for right in range(len(s)):
        c = s[right]
        count[c] = count.get(c, 0) + 1
        if count[c] > max_freq:
            max_freq = count[c]
        while (right - left + 1) - max_freq > k:
            count[s[left]] -= 1
            left += 1
        if right - left + 1 > best:
            best = right - left + 1
    return best

