solution:
def num_subarray_sum_equals_k(nums, k):
    count = {0: 1}
    prefix = 0
    total = 0
    for i in range(len(nums)):
        prefix += nums[i]
        total += count.get(prefix - k, 0)
        count[prefix] = count.get(prefix, 0) + 1
    return total
